// v1.3：強化 prompt（few-shot + 禁 others）+ 改善 fallback 命名

const GEMINI_API_KEY = '__GEMINI_API_KEY__';
const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const items = $input.all();
const allReadItems = $('Read 所有檔案').all();
const results = [];

// Fallback 命名：去掉開頭編號 + 符號（01提示詞 → 提示詞 / 2024-Q3報告 → Q3報告）
function cleanLeadingDigits(name) {
  const noExt = name.replace(/\.[^.]+$/, '');
  const cleaned = noExt.replace(/^[\d\s\-_.()【】]+/, '').trim();
  return cleaned || noExt;  // 全是數字時保留原樣
}

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binFileName = item.binary?.data?.fileName;
  let readItem = allReadItems.find(r => r?.json?.fileName === binFileName) || allReadItems[i];
  if (!readItem?.binary?.data) continue;

  const originalName = readItem.json.fileName || 'unknown';
  const fileExt = (readItem.json.fileExtension || '').toLowerCase();

  // 副檔名快速分類（圖片直接歸 images，跳過 AI）
  const imgExts = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'heic', 'svg', 'bmp', 'tiff'];
  let category = null;
  if (imgExts.includes(fileExt)) category = 'images';

  let newName = originalName;
  let aiResp = '';
  let aiError = null;
  let aiUsed = false;

  if (!category) {
    // 取內文 — PDF 路徑在 .text，純文字路徑在 .data
    let rawText = item.json.text ?? item.json.data ?? '';
    if (typeof rawText !== 'string') rawText = String(rawText);

    // 亂碼偵測：算可印字（中英數標點全形等）佔比；< 70% 視為二進制亂碼，丟掉
    let usableText = '';
    if (rawText.length > 0) {
      const printableMatches = rawText.match(/[\u4e00-\u9fff\u3000-\u303f\uff00-\uffefa-zA-Z0-9\s.,!?;:()\[\]{}\-+="'\/_*&%$#@~|<>]/g);
      const ratio = printableMatches ? printableMatches.length / rawText.length : 0;
      if (ratio > 0.7) usableText = rawText.substring(0, 1500);
    }

    const docxHint = ['docx', 'xlsx', 'pptx'].includes(fileExt) ? '\n注意：這是 Office 檔（' + fileExt + '），無法擷取內文，請用檔名分類。' : '';
    const contentPart = usableText 
      ? '\n內容摘要：' + usableText 
      : '\n（無法擷取內文，請憑檔名與副檔名分類）';

    const prompt = '你是檔案歸檔助手。對下面的文件分類成 6 類之一，並取一個語意化檔名。\n\n' +
      '**類別定義**（看不出明確類型時優先選 docs；only fallback 到 others 在真的什麼都不像）：\n' +
      '- contracts：合約 / 協議 / NDA / 條款 / 授權書 / 同意書\n' +
      '- invoices：發票 / 收據 / 報價單 / 估價單 / 帳單 / 對帳單 / 訂單\n' +
      '- presentations：簡報 / 投影片 / 提案 / pitch deck（檔名常含「簡報」「pitch」「proposal」「PPT」「kickoff」）\n' +
      '- docs：**所有文字內容文件**（手冊 / 說明書 / 筆記 / 會議記錄 / 課程教材 / 教學講義 / 操作指南 / 規格書 / 報告 / brief / 草稿 / 任何 .txt/.md/.docx）\n' +
      '- images：圖片 / 截圖 / 設計稿（這個 workflow 通常副檔名直送，不會問到你）\n' +
      '- others：**真的什麼都不像時才選**（如 .zip / .exe / 加密檔 / 內容明顯不是商業文件）\n\n' +
      '**範例**：\n' +
      '- 合約_NDA_客戶A.pdf → {"category":"contracts","newName":"' + today + '_合約_客戶A NDA"}\n' +
      '- Q3 報價單.xlsx → {"category":"invoices","newName":"' + today + '_報價_Q3"}\n' +
      '- 客戶提案 v3.pptx → {"category":"presentations","newName":"' + today + '_簡報_客戶提案"}\n' +
      '- 01提示詞基礎.docx → {"category":"docs","newName":"' + today + '_教材_提示詞基礎"}\n' +
      '- 會議記錄-0420.md → {"category":"docs","newName":"' + today + '_紀錄_會議"}\n' +
      '- spec.txt → {"category":"docs","newName":"' + today + '_規格_說明"}\n\n' +
      '**輸出規則**：嚴格只回單行 JSON，不要任何前後說明，不要 markdown 包裹。\n' +
      '格式：{"category":"xxx","newName":"' + today + '_類型_關鍵字"}\n\n' +
      '<文件>\n檔名：' + originalName + '\n副檔名：' + fileExt + docxHint + contentPart + '\n</文件>';

    aiUsed = true;
    try {
      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
        headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
        body: {
          contents: [{ role: 'user', parts: [{ text: prompt }] }],
          generationConfig: { temperature: 0.2, maxOutputTokens: 300, thinkingConfig: { thinkingBudget: 0 } }
        },
        json: true,
        timeout: 30000
      });
      aiResp = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
      const m = aiResp.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').match(/\{[\s\S]*?\}/);
      if (m) {
        const parsed = JSON.parse(m[0]);
        if (['contracts','invoices','presentations','docs','images','others'].includes(parsed.category)) category = parsed.category;
        if (parsed.newName) newName = parsed.newName;
      } else {
        aiError = 'no JSON match in response';
      }
    } catch (err) {
      aiError = err.message || String(err);
    }
  }

  // 如果 AI 失敗或沒給 newName，用清理過的原檔名 + 日期
  if (newName === originalName) {
    newName = today + '_' + cleanLeadingDigits(originalName);
  }

  if (!category) category = 'others';
  newName = newName.replace(/[\\/:*?"<>|]/g, '_').substring(0, 100);
  // 兜底：確認有日期前綴
  if (!newName.match(/^\d{8}_/)) newName = today + '_' + newName;
  // 兜底：確認有正確副檔名
  if (fileExt && !newName.toLowerCase().endsWith('.' + fileExt)) newName = newName + '.' + fileExt;

  results.push({
    json: {
      originalName, category, newName,
      newPath: '/files/shared/client-organized/' + category + '/' + newName,
      indexLine: '- **' + category + '** · ' + newName + ' ← ' + originalName,
      aiUsed, aiError,
      aiRespPreview: aiResp.substring(0, 300)
    },
    binary: readItem.binary
  });
}

return results;

// 組 Markdown index + Telegram 通知文
const data = $input.first().json;
const lines = data.indexLine || [];
const cats = data.category || [];
const total = lines.length;
const counts = {};
for (const c of cats) counts[c] = (counts[c] || 0) + 1;

const today = new Date().toISOString().slice(0, 10);
const markdown = '# 客戶資料夾整理交接包 · ' + today + '\n\n' +
  '總共整理 ' + total + ' 份檔案。\n\n' +
  '## 分類統計\n' + Object.entries(counts).map(([k, v]) => '- ' + k + '：' + v + ' 份').join('\n') + '\n\n' +
  '## 檔案清單\n' + lines.join('\n') + '\n\n' +
  '---\n_自動產生於 ' + new Date().toLocaleString('zh-TW') + '_';

const tgMsg = '✅ 客戶資料夾整理完成\n\n' +
  '總計：' + total + ' 份\n' +
  Object.entries(counts).map(([k, v]) => k + '：' + v).join(' / ') + '\n\n' +
  '完整清單：shared/client-organized/_index.md';

return [{
  json: { tgMsg, indexPath: '/files/shared/client-organized/_index.md', total },
  binary: {
    data: {
      data: Buffer.from(markdown).toString('base64'),
      mimeType: 'text/markdown',
      fileName: '_index.md'
    }
  }
}];
